class Solution {
public:
    string discountPrices(string sentence, int discount) {
        stringstream ss(sentence);
        string word, res = "";
        while (ss >> word) {
            if (word.size() > 1 && word[0] == '$') {
                string price = word.substr(1);
                double val = stod(price);
                val *= (100 - discount) / 100.0;
                res += "$" + to_string((int)(val * 100 + 0.5) / 100.0) + " ";
            } else {
                res += word + " ";
            }
        }
        res.pop_back();
        return res;
    }
};
